  test("spread_with_variable_as_last_element") {
    assertCompresses(
      input = """var values = [4, 5, 6];
        var a = [1, 2, 3, ...values]""".stripMargin.trim,
      expected = """var values = [4, 5, 6];
        var a = [1, 2, 3, ...values]""".stripMargin.trim,
      options = AllOff
    )
  }

